        OUR_MITHRAN_MERCENARIES_ENJOY_BEING_SENT_TO_FARAWAY                  = 8632,  -- Our Mithran Mercenaries enjoy being sent to faraway places. It gives them time to take their naps, hunt their mice, and go on their chases.
        MAYBE_IT_S_TO_THE_LACK_OF_CONFIDENCE                                 = 8633,  -- Maybe it's to the lack of confidence that you can give thanks for the drastic fall of morale in your pathetic ranks.
        ID_8634                                                              = 8634,  -- ...
        YES_BUT_HIRING_MERCENARIES_CAN_BE_QUITE_THE                          = 8635,  -- Yes, but hiring mercenaries can be quite the burden on the Federation's treasury, can it not?
        YES_BUT_HIRING_MERCENARIES_CAN_BE_QUITE_THE_2                        = 8636,  -- Yes, but hiring mercenaries can be quite the burden on the Federation's treasury, can it not?
        THE_MORE_REGIONS_UNDER_YOUR_NATION_S_CONTROL                         = 8637,  -- The more regions under your nation's control, the more mercenaries you must hire. And before you realize it, your vaults will be empty.
        I_SUSPECT_THAT_THE_CONQUEST_IS_TAKING_ITS                            = 8638,  -- I suspect that the conquest is taking its toll on the Federation.
        WELL_WE                                                              = 8639,  -- Well, we...
        OHOHOHOHO_IN_A_MATTER_OF_MONTHS_OUR_WISHY                            = 8640,  -- Ohohohoho! In a matter of months, our wishy-worries will be gone, When our Outland regions are patrolled by automatons.
        OPERATION_COSTS_WILL_STAY_LOWER_THAN_LOW_AND                         = 8641,  -- Operation costs will stay lower than low. And into our vaults the gil shall flow. Ohoho!
        SHANTOTTO                                                            = 8642,  -- Shantotto!
        IF_YOU_WISH_WINDURST_CAN_ALSO_BUILD_SOME                             = 8643,  -- If you wish, Windurst can also build some for use by the king and the president. All for a small fee payable in five easy installments.
        OHOHOHOHO_IN_A_MATTER_OF_MONTHS_OUR_WISHY_2                          = 8644,  -- Ohohohoho! In a matter of months, our wishy-worries will be gone, when our Outland regions are patrolled by automatons.
        OPERATION_COSTS_WILL_STAY_LOWER_THAN_LOW_AND_2                       = 8645,  -- Operation costs will stay lower than low. And into our vaults the gil shall flow. Ohoho!
        WHILE_WE_APPRECIATE_THE_CONCERN_FROM_DESTIN_S                        = 8646,  -- While we appreciate the concern from Destin's baby and Karst's pet, I don't think Windurst will be taking any drastic actions yet.
        BUT_IF_YOU_WISH_WE_COULD_BUILD_SOME                                  = 8647,  -- But if you wish, we could build some Cardians for use by the king and the president. All for a small fee payable in five easy installments. O`hohohohoho!
        THAT_SOUNDS_LIKE_A_LOVELY_PLAN_MINISTER_SHANTOTTO                    = 8648,  -- That sounds like a lovely plan, Minister Shantotto.
        BUT_WOULDN_T_THE_USE_OF_AUTOMATONS_IN                                = 8649,  -- But wouldn't the use of automatons in the conquest be in violation of the Treaty of Nations...?
        HMPH_AND_I_HAVE_HEARD_MANY_A_TALE                                    = 8650,  -- Hmph. And I have heard many a tale of those walking scarecrows turning on their masters...
        LIKE_FATHER_LIKE_SON_I_SAY_I_WOULD                                   = 8651,  -- Like father, like son, I say. I would not trust a lump of rubbish made by one of you lunatics any more than I would trust one of you lunatics!
        HOW_CAN_ONE_CALL_A_SOLDIER_THAT_DOES                                 = 8652,  -- How can one call a soldier that does not obey his leader a soldier? And how can one call a leader who cannot control his soldiers a leader?
        OOH_SOMEBODY_S_IN_A_BAD_MOOD                                         = 8653,  -- Ooh, somebody's in a bad mood...
        PRINCE_TRION_YOU_CERTAINLY_DID_NOT_BRING_UP                          = 8654,  -- Prince Trion. You certainly did not bring up this issue without having a solution in mind.
        EXACTLY_YOU_D_BETTER_HAVE_SOMETHING_INTERESTING_TO                   = 8655,  -- Exactly! You'd better have something interesting to say. Or Ajido and I will pack up our things and be on our way.
        RECENTLY_ONE_OF_OUR_ROYAL_KNIGHTS_MADE_HIS                           = 8656,  -- Recently one of our Royal Knights made his return journey from our kingdom's territories to the north--Lord Excenmille.
        EXCENMILLE_THE_MAN_WHO_AFTER_THE_GREAT_WAR                           = 8657,  -- Excenmille? The man who, after the Great War, took a handful of soldiers and successfully invaded the Orcish Empire using guerilla tactics?
        YES_SWORD_IN_HAND_DONNING_ARMOR_STAINED_WITH                         = 8658,  -- Yes. Sword in hand, donning armor stained with the blood of a thousand foes, he returned to his homeland for the first time in twenty years...and was shocked at what he found lurking beyond its gates.
        FOREIGN_MERCHANTS_OF_ALL_SHAPES_AND_SIZES_PEDDLING                   = 8659,  -- Foreign merchants of all shapes and sizes peddling their trinkets. Scruffy adventurers shouting out their petty problems as they walked freely among the streets and alleys. Local shopkeeps and Temple Knights laughing as they mingled with the scum washed up from all corners of the continent.
        EXCENMILLE_WAS_FURIOUS                                               = 8660,  -- Excenmille was furious.
        WHY_WOULD_HE_BE_FURIOUS_THE_INFLUX_OF                                = 8661,  -- Why would he be furious? The influx of adventurers has revitalized your nation.
        ACCORDING_TO_EXCENMILLE_TWENTY_FIVE_YEARS_AGO_A                      = 8662,  -- According to Excenmille, twenty-five years ago, a union among the children of Altana was necessary to defeat the armies of darkness.
        HOWEVER_NOW_THAT_THE_THREAT_HAS_GONE_THERE                           = 8663,  -- However, now that the threat has gone, there is no reason for San d'Oria's citizens to be brushing shoulders with the common folk of other nations. It is this symbiotic relationship that plagues the Kingdom and keeps the once mighty red lion shackled down.
        THAT_SEEMS_LIKE_QUITE_AN_ANACHRONOUS_OPINION                         = 8664,  -- That seems like quite an anachronous opinion...
        EXCENMILLE_S_WAY_OF_THINKING_MAY_SEEM_OUT                            = 8665,  -- Excenmille's way of thinking may seem out-of-date, but his logic cannot be denied. Ever since the opening of our gates to outsiders, the quality of our knights has fallen dramatically.
        I_M_TIRED_OF_HEARING_STORIES_ABOUT_SOME                              = 8666,  -- ... I'm tired of hearing stories about some pumpkin-bumpkin knight. Are you going to get to the point, or are we going to be here all night?
        EXCENMILLE_OFFERED_ME_WITH_THE_FOLLOWING_SUGGESTION                  = 8667,  -- Excenmille offered me with the following suggestion...
        REVIVE_CONFLICT                                                      = 8668,  -- Revive Conflict!
        ID_8669                                                              = 8669,  -- ...
        ID_8670                                                              = 8670,  -- ...!?
        C_CONFLICT_A_SERIES_OF_GAMES_BASED_ON                                = 8671,  -- C-Conflict!? A series of games based on battle exercises, played by select heroes from each of the nations...
        DUE_TO_THE_EXTREME_LEVEL_OF_DANGER_INVOLVED                          = 8672,  -- Due to the extreme level of danger involved, it was banned well before the Great War. You are not suggesting that we reinstate Conflict, are you?
        THAT_IS_WHAT_I_PROPOSE                                               = 8673,  -- That is what I propose.
        CONFLICT_AN_INTERESTING_IDEA                                         = 8674,  -- Conflict... An interesting idea...
        THERE_WAS_ONCE_A_TIME_WHEN_CONFLICT_IGNITED                          = 8675,  -- There was once a time when Conflict ignited the spirits of the people of Bastok--players and fans alike.
        HOWEVER_AFTER_NUMEROUS_ACCIDENTS_THE_GAMES_WERE_DEEMED               = 8676,  -- However, after numerous accidents, the games were deemed a bad influence on the Republic's image, and were banned by law.
        IF_CONFLICT_WAS_REINSTATED_IT_COULD_RE_IGNITE                        = 8677,  -- If Conflict was reinstated, it could re-ignite the flames in the hearts of all Bastokers and renew their faith in the Republican Army. Morale would be restored, and our problems solved.
        PRINCE_TRION_PRINCE_TRION_IF_THAT_S_ALL                              = 8678,  -- Prince Trion, Prince Trion. If that's all that you wanted to say, you didn't have to go beat around the bush all day.
        WINDURST_WELCOMES_CONFLICT_WITH_OPEN_ARMS_A_LITTLE                   = 8679,  -- Windurst welcomes Conflict with open arms! A little feuding fun could do no harm.
        SHANTOTTO_2                                                          = 8680,  -- Shantotto!?
        OH_THERE_S_NOTHING_TO_GET_ALL_EXCITED                                = 8681,  -- Oh, there's nothing to get all excited about. The forces of Windurst are in good hands. A couple of knutty knights and measly musketeers are no match for Shantotto's superior battle plans.
        THE_FORCES_OF_WINDURST_ARE_IN_GOOD_HANDS                             = 8682,  -- The forces of Windurst are in good hands. A couple of knutty knights and measly musketeers are no match for Shantotto's superior battle plans.
        AND_ONCE_WE_GET_OUR_FEARLESS_LOYAL_ADVENTURERS                       = 8683,  -- And once we get our fearless loyal adventurers to help, it will be your two nations letting out cries and yelps.
        IF_SAN_D_ORIA_AND_WINDURST_HAVE_AGREED                               = 8684,  -- If San d'Oria and Windurst have agreed to participate, the president is sure to grant his approval.
        AND_I_KNOW_OUR_ADVENTURERS_WILL_BE_MORE                              = 8685,  -- And I know our adventurers will be more than happy to take up their swords for the Republic.
        EXCELLENT_I_LOOK_FORWARD_TO_MEETING_YOU_ALL                          = 8686,  -- Excellent. I look forward to meeting you all again on the battlefield.
        WELL_IT_IS_A_RARE_OCCASION_THAT_ALL                                  = 8687,  -- Well... It is a rare occasion that all three nations agree on an issue.
        UNFORTUNATELY_DUCAL_LAW_PREVENTS_JEUNO_FROM_PARTICIPATING_IN         = 8688,  -- Unfortunately, ducal law prevents Jeuno from participating in such matters.
        HOWEVER_WE_WILL_ASSIGN_OFFICIALS_TO_TAKE_PART                        = 8689,  -- However, we will assign officials to take part as Heralds and watch over the games.
        I_HAVE_NO_OBJECTIONS_NOW_LET_US_RETURN                               = 8690,  -- I have no objections. Now let us return to our nations and begin with the preparations.
        THEN_IT_HAS_BEEN_DECIDED_SIR_WOLFGANG                                = 8691,  -- Then it has been decided. Sir Wolfgang.
        AHEM_THEN_IF_THERE_IS_NOTHING_FURTHER_I                              = 8692,  -- Ahem. Then, if there is nothing further, I call the 136th Conquest Evaluation Assembly to a close.
        THOUGH_I_D_RATHER_BE_SITTING_ON_THE                                  = 8693,  -- Though I'd rather be sitting on the beach, catching some sun, sometimes these stuffy-snuffy meetings can be kind of fun!
        THOUGH_I_D_RATHER_BE_SITTING_ON_THE_2                                = 8694,  -- Though I'd rather be sitting on the beach, catching some sun, sometimes these stuffy-snuffy meetings can be kind of fun!
        I_COULD_TAKE_UP_MY_STAFF_AND_PARTICIPATE                             = 8695,  -- I could take up my staff and participate in Conflict myself, but my super-duper whammy-slammy spells would be bad for my opponents' health! Ohohohohoho!
        WHAT_DO_YOU_WISH_TO_KNOW_ABOUT_BASIC                                 = 8696,  -- What do you wish to know about? Basic rules. About the Petra. About Sprint. About Scout. About Gate Breach. About area-specific rules. About returning to battle. About special rules. Nothing at the moment.
        BALLISTA_IS_AN_EXERCISE_ONCE_USED_BY_THE                             = 8697,  -- Ballista is an exercise once used by the San d'Orian armies to train the Royal Knights in the art of the siege. The word ballista means to throw a stone, and the game has been a part of Vana'dielian military history for centuries.
        THE_RULES_ARE_SIMPLE_BALLISTA_IS_PLAYED_BY                           = 8698,  -- The rules are simple. Ballista is played by two teams over a number of hours (Vana'diel time). The team with the most points at the end of the match is the victor.
        PLAYERS_FROM_BOTH_TEAMS_MUST_SEARCH_FOR_PETRAS                       = 8699,  -- Players from both teams must search for Petras that a Herald has buried in various locations across the battlefield. The players must then take these stones and throw them into targets known as Rooks.
        THESE_ROOKS_CAN_APPEAR_IN_VARIOUS_LOCATIONS_AROUND                   = 8700,  -- These Rooks can appear in various locations around the battlefield, and both teams are allowed to throw their Petras into them.
        FINALLY_A_PLAYER_S_STRENGTH_IS_ADJUSTED_DEPENDING                    = 8701,  -- Finally, a player's strength is adjusted depending on his or her level. It is felt that this ultimately allows for a more balanced battle.
        PETRAS_CAN_BE_BURIED_ANYWHERE_ONCE_A_PLAYER                          = 8702,  -- Petras can be buried anywhere. Once a player believes he or she has found one, the Quarry (/quarry) command should be used to dig up the area at his or her feet.
        SOMETIMES_A_PLAYER_MAY_FIND_ITEMS_OTHER_THAN                         = 8703,  -- Sometimes a player may find items other than Petras, such as potions. These temporary items can only be used during the current match (or Best of Three series).
        PLAYERS_CAN_CARRY_MORE_THAN_ONE_PETRA_BUT                            = 8704,  -- Players can carry more than one Petra, but they cannot throw the stones away once they have obtained them. However, players will lose their Petras if they: (1) Successfully throw them into a rook. (2) Leave the area. (3) Are knocked out.
        BUT_DON_T_FORGET_A_PLAYER_WILL_BE                                    = 8705,  -- But don't forget, a player will be unable to use the Sprint command while in possession of a Petra. And, players can only use the Scout command if they carry one of the stones.
        AS_ONE_CAN_SEE_CAREFUL_PLANNING_AND_IMPECCABLE                       = 8706,  -- As one can see, careful planning and impeccable timing are the keys to victory.
        ALL_PARTICIPANTS_OF_BALLISTA_WILL_HAVE_THE_ABILITY                   = 8707,  -- All participants of Ballista will have the ability to use the Sprint command. This will temporarily increase one's movement speed, creating a better chance to find and obtain Petras.
        HOWEVER_REMEMBER_THAT_ONCE_A_PLAYER_HAS_OBTAINED                     = 8708,  -- However, remember that once a player has obtained a Petra, he or she will be unable to use the Sprint command. In its place, though, one may use the Scout command.
        THE_LOCATIONS_OF_THE_ROOKS_ARE_CONSTANTLY_CHANGING                   = 8709,  -- The locations of the Rooks are constantly changing. This makes it quite difficult to find the targets by just randomly walking about the area.
        COMMUNICATION_WITH_ONE_S_TEAM_MEMBERS_IS_OF                          = 8710,  -- Communication with one's team members is, of course, one way to locate Rooks. However, another way is by using the Scout command. This will inform a player of the approximate location of the nearest Rook.
        FINALLY_SCOUT_CAN_ONLY_BE_USED_WHEN_A                                = 8711,  -- Finally, Scout can only be used when a player is carrying a Petra. Because Sprint cannot be used at this time, players must be weary of approaching enemies.
        SO_A_PETRA_HAS_BEEN_OBTAINED_AND_A                                   = 8712,  -- So, a Petra has been obtained and a Rook located. Now all that's left is tossing the stone in, right? Wrong.
        THERE_IS_ONE_ASPECT_OF_BALLISTA_THAT_HAS                             = 8713,  -- There is one aspect of Ballista that has yet to be mentioned...and this is where the real battle begins.
        TO_THROW_A_PETRA_INTO_A_ROOK_A                                       = 8714,  -- To throw a Petra into a Rook, a player must first wait until the Rook's gate is open. This takes impeccable timing, as the gate is only open for a short while.
        BUT_NOT_JUST_ANYONE_CAN_SCORE_POINTS_THIS                            = 8715,  -- But not just anyone can score points this way. A player must first take down a member of the opposing team and achieve Gate Breach status. Only then will his or her shots count.
        THIS_EXTREME_METHOD_OF_COMBAT_IS_WHAT_MADE                           = 8716,  -- This extreme method of combat is what made the ancient game of Ballista famous, and transformed its participants into heroes.
        RUNNING_ABOUT_LOOKING_FOR_STONES_IS_NO_DIFFERENT                     = 8717,  -- Running about looking for stones is no different from a child's game of hide-and-seek. Knowing when to strike is what separates the men from the boys.
        THE_FOLLOWING_MATCH_TYPES_ARE_AREA_SPECIFIC_ALL                      = 8718,  -- The following match types are area-specific: All or Nothing (one match) * Normal Items Allowed: Jugner Forest All or Nothing (one match) * Normal Items Restricted: Pashhow Marshlands Best of Three (three matches) * Normal Items Allowed: Meriphataud Mountains
        BEST_OF_THREE_SERIES_RULES_ARE_AS_FOLLOWS                            = 8719,  -- Best of Three series rules are as follows: Winning a match will earn a nation one match point. The nation with the most match points at the end of the series will be declared the victor. Winning the third and final match and producing the high scorer will result in two match points awarded. This allows both sides the chance for come-from-behind victories.
        BETWEEN_EACH_OF_THE_MATCHES_A_SHORT_INTERVAL                         = 8720,  -- Between each of the matches, a short interval will be implemented. During this interval, Invisible and Sneak will be cast on all participants. We suggest this time be used to discuss strategies with the other members of your nation's forces.
        PLAYERS_WILL_BE_FORBIDDEN_FROM_USING_ANY_ITEMS                       = 8721,  -- Players will be forbidden from using any items they bring to the battlefield. Only temporary items that are quarried may be used. A total of fifteen temporary items (though only one of each type) can be carried.
        WHEN_THIS_RULE_IS_IN_EFFECT_ALL_PLAYERS                              = 8722,  -- When this rule is in effect, all players will be presented with five complimentary temporary items at the beginning of the match.
        FOR_MORE_INFORMATION_ON_TEMPORARY_ITEMS_REFER_TO                     = 8723,  -- For more information on temporary items, refer to the special rules.
        AFTER_BEING_KO_D_IF_A_PLAYER_CHOOSES                                 = 8724,  -- After being KO'd, if a player chooses to be revived at the spot he was defeated, 100% of all HP and 50% of all MP will be restored. In addition, the player will maintain 50% of the TP he had earned.
        IF_A_PLAYER_CHOOSES_TO_RETURN_TO_THEIR                               = 8725,  -- If a player chooses to return to their force's camp, HP and MP will be fully restored, but all TP will be lost.
        PLEASE_NOTE_THAT_MANY_OF_THE_RULES_PREVIOUSLY                        = 8726,  -- Please note that many of the rules previously considered special have been fully implemented. Also, several new special rules have been added.
        LEARN_ABOUT_WHICH_SPECIAL_RULES_TEMPORARY_ITEMS_BALLISTA             = 8727,  -- Learn about which special rules? Temporary items. Ballista Points. Scoring restrictions. Gate Breach radius expansion. Resistance to Sleep. Open entries. Minimum level restrictions. Re-entry restrictions. Participant & Rook numbers. Experience Points. Return.
        PREVIOUSLY_PARTICIPANTS_IN_BALLISTA_WERE_REQUIRED_TO_USE             = 8728,  -- Previously, participants in Ballista were required to use an item the moment they dug it up using the /quarry command. However, players can now stock these items as temporary items for use at any time during the match.
        PLAYERS_CAN_HOLD_UP_TO_TEN_TEMPORARY_ITEMS                           = 8729,  -- Players can hold up to ten temporary items, but only one of each type. If a player finds an item that they already possess, they must use it immediately or throw it away.
        IF_PLAYERS_WHO_POSSESS_TEN_TEMPORARY_ITEMS_FIND                      = 8730,  -- If players who possess ten temporary items find an item that they have not already obtained, they will also have the option to exchange it with one of their current items.
        ALSO_PLAYERS_WILL_NOT_AT_ANY_TIME_BE                                 = 8731,  -- Also, players will not, at any time, be allowed to trade temporary items. However, there are items that can be used on other Ballista participants. Please note that players may not be able to use these special items as soon as they are quarried.
        FINALLY_THE_HERALDS_WILL_COLLECT_TEMPORARY_ITEMS_WHEN                = 8732,  -- Finally, the Heralds will collect temporary items when the match (the third in a Best of Three series) has concluded.
        BALLISTA_POINTS_ARE_REWARDED_TO_EACH_COMPETITOR_BASED                = 8733,  -- Ballista Points are rewarded to each competitor based on his or her performance in a single Ballista match. The maximum number of points that can be accumulated per match is #.
        WHILE_IT_IS_TAKEN_INTO_CONSIDERATION_SCORING_PETRAS                  = 8734,  -- While it is taken into consideration, scoring Petras is not the only way to earn Ballista Points. Assisting allies and defeating members of the enemy forces can also earn a high score.
        BALLISTA_POINTS_CAN_BE_TRADED_FOR_SPECIAL_VOUCHERS                   = 8735,  -- Ballista Points can be traded for special vouchers, which may be exchanged for free temporary items at the start of new matches.
        HOWEVER_REMEMBER_THAT_DEPENDING_ON_THE_LEVEL_RESTRICTION             = 8736,  -- However, remember that depending on the level restriction of the match, certain vouchers will not be redeemed at the beginning of a match. Speak with a Marshal directly after a match to register your points.
        PLAYERS_WILL_ONLY_BE_ALLOWED_TO_SCORE_UP                             = 8737,  -- Players will only be allowed to score up to five Petras at a time. Also, a player's Gate Breach status will be automatically disengaged if a Petra is not scored within a certain amount of time. The amount of time is increased for those members of the team currently behind in points.
        ALL_ALLIES_WITHIN_A_CERTAIN_RADIUS_WILL_ACHIEVE                      = 8738,  -- All allies within a certain radius will achieve Gate Breach status when a member of the enemy forces is defeated.
        PLAYERS_RESISTANCE_TO_SLEEP_WILL_BE_INCREASED                        = 8739,  -- Players' resistance to sleep will be increased.
        DURING_THE_ENTRY_PERIOD_FROM_ALL_ADVENTURERS_WILL                    = 8740,  -- During the entry period, from #:, all adventurers will be allowed to join the forces with the smallest number of participants, regardless of allegiance. Open entries will be accepted until both sides have reached maximum capacity.
        IN_ORDER_TO_ENSURE_BALANCED_MATCHES_THE_FOLLOWING                    = 8741,  -- In order to ensure balanced matches, the following level limits are enforced: Level 30 matches: 1`30
        LEVEL_40_MATCHES_31_40_LEVEL_50_MATCHES                              = 8742,  -- Level 40 matches: 31`40 Level 50 matches: 41`50 Level 60 matches: 51`60 Unrestricted matches: 61`
        PLEASE_NOTE_THAT_ANY_PARTICIPANT_WHO_CANCELS_HIS                     = 8743,  -- Please note that any participant who cancels his or her registration will not be allowed to re-apply for the same match.
        WHEN_THE_TOTAL_NUMBER_OF_PARTICIPANTS_IN_A                           = 8744,  -- When the total number of participants in a match is less than 40, the location of the two camps will be adjusted. Also in this case, the number of Rooks will be reduced to two.
        ANY_ADVENTURER_WHOSE_MAIN_LEVEL_IS_OVER_30                           = 8745,  -- Any adventurer whose main level is over 30 will receive EXP for participating in a Ballista match. However, no EXP will be rewarded if the adventurer fails to actively take part in the match.
        READ_WHICH_CHAPTER_ON_B_P_RANKING_BASIC                              = 8746,  -- Read which chapter on B.P. Ranking? Basic Information. Registering Points. Rewards. Chevron & Title List. None.
        BALLISTA_POINT_RANKING_IS_BASED_UPON_ALL_BALLISTA                    = 8747,  -- Ballista Point Ranking is based upon all Ballista Points registered from the past ten matches in each of the three participating battle areas.
        ANYONE_WHO_WISHES_TO_TAKE_PART_IN_THE                                = 8748,  -- Anyone who wishes to take part in the ranking needs to register his/her] points within four hours (Vana'diel time) from the end of the previous match.
        AFTER_THE_REGISTRATION_PERIOD_ENDS_PLAYERS_CAN_COMPARE               = 8749,  -- After the registration period ends, players can compare their record with those of the previous nine matches.
        IF_AT_ANY_TIME_A_PLAYER_RANKS_IN                                     = 8750,  -- If, at any time, a player ranks in the top ten (overall) or first for a specific job, he/she] will have the opportunity to receive a special chevron as well as a new title.
        THERE_ARE_FOUR_TYPES_OF_CHEVRONS_AND_TITLES                          = 8751,  -- There are four types of chevrons and titles awarded to top-ten players (gold/mythril/silver/bronze), as well as twenty-two different types awarded for outstanding performances by players of each of the twenty-two jobs.
        WEARING_A_CHEVRON_DURING_A_BALLISTA_MATCH_WILL                       = 8752,  -- Wearing a chevron during a Ballista match will automatically change a player's current title. If a player wishes to possess this title after a match as well, he/she] must contact a certain bard in San d'Oria.
        ALSO_WHILE_WEARING_A_CHEVRON_PLAYERS_WILL_BE                         = 8753,  -- Also, while wearing a chevron, players will be able to trade Ballista Points for temporary items not available to all players.
        HOWEVER_THE_RULES_OF_BALLISTA_STATE_THAT_PLAYERS                     = 8754,  -- However, the rules of Ballista state that players may only possess a certain chevron for no longer than one half Vana'diel year. When that time comes, they are required to return the chevron before being allowed to participate in any further matches.
        FINALLY_CHECKING_SOMEONE_DURING_A_BALLISTA_MATCH_WILL                = 8755,  -- Finally, checking someone during a Ballista match will display the total number of chevrons that person has accumulated to date.
        VIEW_WHICH_CHEVRON_TITLE_1ST_OVERALL_2ND_OVERALL                     = 8756,  -- View which chevron/title? 1st (overall). 2nd (overall). 3rd (overall). 4th-10th (overall). 1st (warrior). 1st (monk). 1st (white mage). 1st (black mage). 1st (red mage). 1st (thief). 1st (paladin). 1st (dark knight). 1st (beastmaster). 1st (bard). 1st (ranger). 1st (samurai). 1st (ninja). 1st (dragoon). 1st (summoner). 1st (blue mage). 1st (corsair). 1st (puppetmaster). 1st (dancer). 1st (scholar). 1st (geomancer). 1st (rune fencer). Return.
        KEY_ITEM_TITLE_GOLD_BALLITAR                                         = 8757,  -- Key Item: % Title: Gold Ballitar
        KEY_ITEM_TITLE_MYTHRIL_BALLITAR                                      = 8758,  -- Key Item: % Title: Mythril Ballitar
        KEY_ITEM_TITLE_SILVER_BALLITAR                                       = 8759,  -- Key Item: % Title: Silver Ballitar
        KEY_ITEM_TITLE_BRONZE_BALLITAR                                       = 8760,  -- Key Item: % Title: Bronze Ballitar
        KEY_ITEM_TITLE_SEARINGTAR                                            = 8761,  -- Key Item: % Title: Searingtar
        KEY_ITEM_TITLE_STRIKINGTAR                                           = 8762,  -- Key Item: % Title: Strikingtar
        KEY_ITEM_TITLE_SOOTHINGTAR                                           = 8763,  -- Key Item: % Title: Soothingtar
        KEY_ITEM_TITLE_SABLETAR                                              = 8764,  -- Key Item: % Title: Sabletar
        KEY_ITEM_TITLE_SCARLETTAR                                            = 8765,  -- Key Item: % Title: Scarlettar
