        ALSO_PLEASE_NOTE_THAT_YOU_CANNOT_QUICKEN_YOUR                        = 9063,  -- Also, please note that you cannot quicken your pace using any special abilities while you are in possession of a Flamme.
        IN_THE_EVENT_THAT_NEITHER_SIDE_FULFILLS_THE                          = 9064,  -- In the event that neither side fulfills the conditions for victory, the outcome of the match will be evaluated based on score.
        TEN_POINTS_ARE_AWARDED_TO_EACH_SIDE_FOR                              = 9065,  -- Ten points are awarded to each side for every lit Flammen-Brenner, while one point is awarded whenever a Flamme is captured, used to light a Flammen-Brenner, or recaptured from an opponent. One point is also awarded for protecting the Flammen-Brenner for a certain period of time.
        LIKE_BALLISTA_QUARRY_QUARRY_CAN_BE_USED_WHILE                        = 9066,  -- Like Ballista, quarry (/quarry) can be used while playing Brenner. Participants may use this ability to dig up Petras and temporary items.
        HOWEVER_UNLIKE_BALLISTA_PETRAS_BRENNER_PETRAS_HAVE_NO                = 9067,  -- However, unlike Ballista Petras, Brenner Petras have no effect on the match score. You can trade a Petra to a Pursuivant to recover your HP and MP at no expense to TP.
